def range_summary(nums):
    if not nums:
        return ''
    nums = sorted(set(nums))
    runs = [str(nums[0])]
    for i in range(1, len(nums)):
        if nums[i] == nums[i-1] + 1:
            continue
        elif nums[i] == nums[i-1]:
            runs[-1] += f'-{nums[i]}'
        else:
            runs.append(str(nums[i]))
    return ', '.join(runs)
